public mutating func next() -> [Base.Element]? {
  guard !isFinished else { return nil }
  defer { advance() }
  return indexes.map { i in base[i] }
}

@inlinable
    public init(initialCapacity: Int) {
        let capacity = Int(UInt32(initialCapacity).nextPowerOf2())
        self.headBackingIndex = 0
        self.tailBackingIndex = 0
        self._buffer = ContiguousArray<Element?>(repeating: nil, count: capacity)
        assert(self._buffer.count == capacity)
    }

for sublayer in sublayers ?? [] {
  allSublayers.append(sublayer)
  allSublayers.append(contentsOf: sublayer.allSublayers)
}

if let containerID = (node.representedObject as? ContainerIdentifiable)?.containerID {
	if expandedTable.contains(containerID) {
		outlineView.expandItem(node)
	} else {
		outlineView.collapseItem(node)
	}
}

if startRow == numberOfRows {
	// Last item is selected, so start at the beginning if we allow wrapping
	orderedRows = wrapping ? Array(0..<numberOfRows) : []
} else {
	// Start at the selection and wrap around to the beginning
	orderedRows = Array(startRow..<numberOfRows) + (wrapping ? Array(0..<startRow) : [])
}

if keyTimes.last != 1.0 {
  keyTimes.append(1.0)
  values.append(values.last!)
  timingFunctions.append(CAMediaTimingFunction(name: .linear))
}

if startValue.cgFloatValue < endValue.cgFloatValue {
  return (start: startValue, end: endValue)
} else {
  return (start: endValue, end: startValue)
}

if Current.isCatalyst {
    refreshBlock()
} else {
    Current.connectivity.syncNetworkInformation {
        refreshBlock()
    }
}

guard let baseURL = connectionInfo.address(for: urlType) else {
    Current.Log.error("No URL available for re-authentication with type \(urlType)")
    showReauthFailureAlert(error: ServerConnectionError.noActiveURL(server.info.name))
    return
}

if !Current.isCatalyst {
    let zoomValue = Current.settingsStore.pinchToZoom ? "true" : "false"
    webView.evaluateJavaScript("setOverrideZoomEnabled(\(zoomValue))", completionHandler: nil)
}

if reason == .settingChange {
    setNeedsStatusBarAppearanceUpdate()
    setNeedsUpdateOfHomeIndicatorAutoHidden()
    updateEdgeToEdgeLayout()
}

if edgeToEdge {
    webViewTopConstraint = webView.topAnchor.constraint(equalTo: view.topAnchor)
    statusBarView.isHidden = true
} else {
    webViewTopConstraint = webView.topAnchor.constraint(equalTo: statusBarView.bottomAnchor)
    statusBarView.isHidden = false
}

if webView.responds(to: #selector(paste(_:))) {
    webView.perform(#selector(paste(_:)), with: nil)
}

guard let webviewURL = server.info.connection.webviewURL() else {
    Current.Log.info("not loading, no url")
    showNoActiveURLError()
    return
}

guard webView.url == nil || webView.url?.baseIsEqual(to: webviewURL) == false else {
    // we also tell the webview -- maybe it failed to connect itself? -- to refresh if needed
    webView.evaluateJavaScript("checkForMissingHassConnectionAndReload()", completionHandler: nil)
    return
}

if Current.isCatalyst {
    loadBlock()
} else {
    Current.connectivity.syncNetworkInformation {
        loadBlock()
    }
}

if node.isGroupItem {
	let cell = outlineView.makeView(withIdentifier: NSUserInterfaceItemIdentifier(rawValue: "HeaderCell"), owner: self) as! NSTableCellView
	configureGroupCell(cell, node)
	return cell
}

if item.action == #selector(copy(_:)) {
	return NSPasteboard.general.canCopyAtLeastOneObject(selectedObjects)
}

if let node = treeController.rootNode.descendantNode(where: { ($0.representedObject as? Account)?.nameForDisplay == accountName }) {
	return node
}

guard let typedLayer = layer as? Self else {
  fatalError("\(Self.self).init(layer:) incorrectly called with \(type(of: layer))")
}

if layer === contentsLayer {
  super.addSublayer(contentsLayer)
} else {
  contentsLayer.addSublayer(layer)
}

if
      renderLayerContents,
      let masks = baseLayerModel.masks?.filter({ $0.mode != .none }),
      !masks.isEmpty
    {
      contentsLayer.mask = MaskCompositionLayer(masks: masks)
    }

if shouldInvertMask {
  let path = CGMutablePath()
  path.addRect(.veryLargeRect)
  path.addPath(maskPath)
  return path
} else {
  return maskPath
}

if gradientFill.hasAlphaComponent {
  alphaGradientLayer = GradientRenderLayer()
  rgbGradientLayer.mask = alphaGradientLayer
} else {
  alphaGradientLayer = nil
}

if gradientStroke.hasAlphaComponent {
  alphaGradientLayer = GradientRenderLayer()
  rgbGradientLayer.mask = alphaGradientLayer
} else {
  alphaGradientLayer = nil
}

@inlinable
    public mutating func modify<Result>(
        _ index: Index,
        _ modifyFunc: (inout Element) throws -> Result
    ) rethrows -> Result {
        try modifyFunc(&self._buffer[index.backingIndex]!)
    }

if
          let strokeIndex = strokesAndFills.firstIndex(where: { $0.item.isStroke }),
          let fillIndex = strokesAndFills.firstIndex(where: { $0.item.isFill })
        {
          strokeIndex < fillIndex
        } else {
          false
        }

for animationLayer in sublayers ?? [] {
  try (animationLayer as? AnimationLayer)?.setupAnimations(context: layerContext)
}
